            {"lov": 'burettslagslova', "paragraf": '4-1', "tittel": 'regelen om at du bare kan eie én andel', "available": True},
            {"lov": 'burettslagslova', "paragraf": '5-1', "tittel": 'hovedregelen om boretten', "available": True},
